fn parse_nul_paths(output: &[u8]) -> Vec<String> {
    output
        .split(|byte| *byte == 0)
        .filter_map(|path| {
            let path = String::from_utf8_lossy(path).to_string();
            (!path.is_empty()).then_some(path)
        })
        .collect()
}

